import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

const Header = () => {
  const { user, isAuthenticated, logout } = useAuth();
  const navigate = useNavigate();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isGamesMenuOpen, setIsGamesMenuOpen] = useState(false);
  const [isToolsMenuOpen, setIsToolsMenuOpen] = useState(false);


  // Close Games and Tools menus when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (isGamesMenuOpen && !event.target.closest('.games-menu')) {
        setIsGamesMenuOpen(false);
      }
      if (isToolsMenuOpen && !event.target.closest('.tools-menu')) {
        setIsToolsMenuOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isGamesMenuOpen, isToolsMenuOpen]);


  const handleLogout = async () => {
    try {
      await logout();
      navigate('/');
    } catch (error) {
      console.error('Logout failed:', error);
    }
  };

  const toggleMobileMenu = () => {
    setIsMobileMenuOpen(!isMobileMenuOpen);
  };

  const toggleGamesMenu = () => {
    setIsGamesMenuOpen(!isGamesMenuOpen);
  };

  const toggleToolsMenu = () => {
    setIsToolsMenuOpen(!isToolsMenuOpen);
  };

  return (
    <header className="bg-white shadow-md">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          {/* Logo */}
          <div className="flex-shrink-0">
            <Link to="/" className="text-2xl font-bold text-blue-600">
              HoB Tools
            </Link>
          </div>

                     {/* Desktop Navigation */}
           <nav className="hidden md:flex space-x-8">
             <Link
               to="/"
               className="text-gray-700 hover:text-blue-600 px-3 py-2 rounded-md text-sm font-medium transition-colors"
             >
               Home
             </Link>
             <Link
               to="/media"
               className="text-gray-700 hover:text-blue-600 px-3 py-2 rounded-md text-sm font-medium transition-colors flex items-center space-x-1"
             >
               <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24">
                 <path d="M8 5v14l11-7z"/>
               </svg>
               <span>Media</span>
             </Link>
             
             {/* Games Dropdown */}
             <div className="relative games-menu">
               <button
                 onClick={toggleGamesMenu}
                 className="text-gray-700 hover:text-blue-600 px-3 py-2 rounded-md text-sm font-medium transition-colors flex items-center space-x-1"
               >
                 <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24">
                   <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/>
                 </svg>
                 <span>Games</span>
                 <svg className="w-3 h-3 ml-1" fill="currentColor" viewBox="0 0 20 20">
                   <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
                 </svg>
               </button>
               
               {isGamesMenuOpen && (
                 <div className="absolute left-0 mt-2 w-48 bg-white rounded-md shadow-lg py-1 z-50 border border-gray-200">
                   <Link
                     to="/games/mines"
                     className="block px-4 py-2 text-sm text-gray-700 hover:bg-gray-100 hover:text-blue-600 transition-colors"
                     onClick={() => setIsGamesMenuOpen(false)}
                   >
                     <div className="flex items-center space-x-2">
                       <span>💣</span>
                       <span>Mines</span>
                     </div>
                   </Link>
                   <Link
                     to="/games/2048"
                     className="block px-4 py-2 text-sm text-gray-700 hover:bg-gray-100 hover:text-blue-600 transition-colors"
                     onClick={() => setIsGamesMenuOpen(false)}
                   >
                     <div className="flex items-center space-x-2">
                       <span>🔢</span>
                       <span>2048</span>
                     </div>
                   </Link>
                 </div>
               )}
             </div>
             
             {/* Tools Dropdown */}
             <div className="relative tools-menu">
               <button
                 onClick={toggleToolsMenu}
                 className="text-gray-700 hover:text-blue-600 px-3 py-2 rounded-md text-sm font-medium transition-colors flex items-center space-x-1"
               >
                 <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24">
                   <path d="M22.7 19l-9.1-9.1c.9-2.3.4-5-1.5-6.9-2-2-5-2.4-7.4-1.3L9 6 6 9 1.6 4.7C.4 7.1.9 10.1 2.9 12.1c1.9 1.9 4.6 2.4 6.9 1.5l9.1 9.1c.4.4 1 .4 1.4 0l2.3-2.3c.5-.4.5-1.1.1-1.4z"/>
                 </svg>
                 <span>Tools</span>
                 <svg className="w-3 h-3 ml-1" fill="currentColor" viewBox="0 0 20 20">
                   <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
                 </svg>
               </button>
               
               {isToolsMenuOpen && (
                 <div className="absolute left-0 mt-2 w-48 bg-white rounded-md shadow-lg py-1 z-50 border border-gray-200">
                   <Link
                     to="/tools/qr-generation"
                     className="block px-4 py-2 text-sm text-gray-700 hover:bg-gray-100 hover:text-blue-600 transition-colors"
                     onClick={() => setIsToolsMenuOpen(false)}
                   >
                     <div className="flex items-center space-x-2">
                       <span>📱</span>
                       <span>QR Generator</span>
                     </div>
                   </Link>
                   <Link
                     to="/tools/encoding"
                     className="block px-4 py-2 text-sm text-gray-700 hover:bg-gray-100 hover:text-blue-600 transition-colors"
                     onClick={() => setIsToolsMenuOpen(false)}
                   >
                     <div className="flex items-center space-x-2">
                       <span>🔤</span>
                       <span>Encoding</span>
                     </div>
                   </Link>
                 </div>
               )}
             </div>
             
             {isAuthenticated && (
               <>
                 <Link
                   to="/dashboard"
                   className="text-gray-700 hover:text-blue-600 px-3 py-2 rounded-md text-sm font-medium transition-colors"
                 >
                   Dashboard
                 </Link>
                 <Link
                   to="/users"
                   className="text-gray-700 hover:text-blue-600 px-3 py-2 rounded-md text-sm font-medium transition-colors"
                 >
                   Users
                 </Link>
                 <Link
                   to="/products"
                   className="text-gray-700 hover:text-blue-600 px-3 py-2 rounded-md text-sm font-medium transition-colors"
                 >
                   Products
                 </Link>
               </>
             )}
           </nav>

                     {/* User Menu / Auth Buttons */}
           <div className="hidden md:flex items-center space-x-4">
             
             {isAuthenticated ? (
               <div className="flex items-center space-x-4">
                 <div className="flex items-center space-x-2">
                   <div className="w-8 h-8 bg-blue-600 rounded-full flex items-center justify-center">
                     <span className="text-white text-sm font-medium">
                       {user?.name?.charAt(0) || 'U'}
                     </span>
                   </div>
                   <span className="text-gray-700 text-sm font-medium">
                     {user?.name || 'User'}
                   </span>
                 </div>
                 <button
                   onClick={handleLogout}
                   className="bg-red-600 hover:bg-red-700 text-white px-4 py-2 rounded-md text-sm font-medium transition-colors"
                 >
                   Logout
                 </button>
               </div>
             ) : (
               <div className="flex space-x-4">
                 <Link
                   to="/login"
                   className="text-blue-600 hover:text-blue-700 px-4 py-2 rounded-md text-sm font-medium transition-colors"
                 >
                   Login
                 </Link>
                 <Link
                   to="/register"
                   className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-md text-sm font-medium transition-colors"
                 >
                   Register
                 </Link>
               </div>
             )}
           </div>

          {/* Mobile menu button */}
          <div className="md:hidden">
            <button
              onClick={toggleMobileMenu}
              className="text-gray-700 hover:text-blue-600 p-2"
            >
              <svg
                className="h-6 w-6"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                {isMobileMenuOpen ? (
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M6 18L18 6M6 6l12 12"
                  />
                ) : (
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M4 6h16M4 12h16M4 18h16"
                  />
                )}
              </svg>
            </button>
          </div>
        </div>

        {/* Mobile Navigation */}
        {isMobileMenuOpen && (
          <div className="md:hidden">
            <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3 border-t border-gray-200">
              <Link
                to="/"
                className="text-gray-700 hover:text-blue-600 block px-3 py-2 rounded-md text-base font-medium"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                Home
              </Link>
               <Link
                 to="/media"
                 className="text-gray-700 hover:text-blue-600 block px-3 py-2 rounded-md text-base font-medium flex items-center space-x-2"
                 onClick={() => setIsMobileMenuOpen(false)}
               >
                 <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24">
                   <path d="M8 5v14l11-7z"/>
                 </svg>
                 <span>Media Player</span>
               </Link>
               
               {/* Games Menu for Mobile */}
               <div className="px-3 py-2">
                 <div className="text-gray-700 text-base font-medium mb-2 flex items-center space-x-2">
                   <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24">
                     <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/>
                   </svg>
                   <span>Games</span>
                 </div>
                 <div className="ml-4 space-y-1">
                   <Link
                     to="/games/mines"
                     className="text-gray-600 hover:text-blue-600 block px-3 py-2 rounded-md text-sm font-medium flex items-center space-x-2"
                     onClick={() => setIsMobileMenuOpen(false)}
                   >
                     <span>💣</span>
                     <span>Mines</span>
                   </Link>
                   <Link
                     to="/games/2048"
                     className="text-gray-600 hover:text-blue-600 block px-3 py-2 rounded-md text-sm font-medium flex items-center space-x-2"
                     onClick={() => setIsMobileMenuOpen(false)}
                   >
                     <span>🔢</span>
                     <span>2048</span>
                   </Link>
                 </div>
               </div>
               
               {/* Tools Menu for Mobile */}
               <div className="px-3 py-2">
                 <div className="text-gray-700 text-base font-medium mb-2 flex items-center space-x-2">
                   <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24">
                     <path d="M22.7 19l-9.1-9.1c.9-2.3.4-5-1.5-6.9-2-2-5-2.4-7.4-1.3L9 6 6 9 1.6 4.7C.4 7.1.9 10.1 2.9 12.1c1.9 1.9 4.6 2.4 6.9 1.5l9.1 9.1c.4.4 1 .4 1.4 0l2.3-2.3c.5-.4.5-1.1.1-1.4z"/>
                   </svg>
                   <span>Tools</span>
                 </div>
                 <div className="ml-4 space-y-1">
                   <Link
                     to="/tools/qr-generation"
                     className="text-gray-600 hover:text-blue-600 block px-3 py-2 rounded-md text-sm font-medium flex items-center space-x-2"
                     onClick={() => setIsMobileMenuOpen(false)}
                   >
                     <span>📱</span>
                     <span>QR Generator</span>
                   </Link>
                   <Link
                     to="/tools/encoding"
                     className="text-gray-600 hover:text-blue-600 block px-3 py-2 rounded-md text-sm font-medium flex items-center space-x-2"
                     onClick={() => setIsMobileMenuOpen(false)}
                   >
                     <span>🔤</span>
                     <span>Encoding</span>
                   </Link>
                 </div>
               </div>
               
               {isAuthenticated ? (
                <>
                  <Link
                    to="/dashboard"
                    className="text-gray-700 hover:text-blue-600 block px-3 py-2 rounded-md text-base font-medium"
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    Dashboard
                  </Link>
                  <Link
                    to="/users"
                    className="text-gray-700 hover:text-blue-600 block px-3 py-2 rounded-md text-base font-medium"
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    Users
                  </Link>
                  <Link
                    to="/products"
                    className="text-gray-700 hover:text-blue-600 block px-3 py-2 rounded-md text-base font-medium"
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    Products
                  </Link>
                  <div className="border-t border-gray-200 pt-4">
                    <div className="flex items-center space-x-2 px-3 py-2">
                      <div className="w-8 h-8 bg-blue-600 rounded-full flex items-center justify-center">
                        <span className="text-white text-sm font-medium">
                          {user?.name?.charAt(0) || 'U'}
                        </span>
                      </div>
                      <span className="text-gray-700 text-sm font-medium">
                        {user?.name || 'User'}
                      </span>
                    </div>
                    <button
                      onClick={() => {
                        handleLogout();
                        setIsMobileMenuOpen(false);
                      }}
                      className="w-full text-left text-red-600 hover:text-red-700 px-3 py-2 rounded-md text-base font-medium"
                    >
                      Logout
                    </button>
                  </div>
                </>
                             ) : (
                 <div className="border-t border-gray-200 pt-4 space-y-2">
                   
                   <Link
                     to="/login"
                     className="text-blue-600 hover:text-blue-700 block px-3 py-2 rounded-md text-base font-medium"
                     onClick={() => setIsMobileMenuOpen(false)}
                   >
                     Login
                   </Link>
                   <Link
                     to="/register"
                     className="bg-blue-600 hover:bg-blue-700 text-white block px-3 py-2 rounded-md text-base font-medium text-center"
                     onClick={() => setIsMobileMenuOpen(false)}
                   >
                     Register
                   </Link>
                 </div>
               )}
            </div>
          </div>
        )}
      </div>
    </header>
  );
};

export default Header;
