// API Configuration
const API_CONFIG = {
  // Backend API base URL - can be configured via environment variables
  BASE_URL: process.env.REACT_APP_API_URL || 'http://localhost:8080',
  
  // API endpoints based on OpenAPI spec
  ENDPOINTS: {
    AUTH: {
      LOGIN: '/auth/login',
      REGISTER: '/auth/register',
      REFRESH: '/auth/refresh',
      ME: '/auth/me',
    },
    DATABASES: {
      LIST: '/databases',
      CREATE: '/databases',
      DELETE: '/databases',
      INIT_TABLES: '/databases/{db_name}/init-tables',
      EXECUTE_SQL: '/databases/{db_name}/execute-sql',
    },
    USERS: {
      LIST: '/api/v1/databases/{db_name}/users',
      CREATE: '/api/v1/databases/{db_name}/users',
      GET: '/api/v1/databases/{db_name}/users/{user_id}',
      UPDATE: '/api/v1/databases/{db_name}/users/{user_id}',
      DELETE: '/api/v1/databases/{db_name}/users/{user_id}',
      POSTS: '/api/v1/databases/{db_name}/users/{user_id}/posts',
    },
    POSTS: {
      LIST: '/api/v1/databases/{db_name}/posts',
      CREATE: '/api/v1/databases/{db_name}/posts',
      GET: '/api/v1/databases/{db_name}/posts/{post_id}',
      UPDATE: '/api/v1/databases/{db_name}/posts/{post_id}',
      DELETE: '/api/v1/databases/{db_name}/posts/{post_id}',
      COMMENTS: '/api/v1/databases/{db_name}/posts/{post_id}/comments',
    },
    COMMENTS: {
      LIST: '/api/v1/databases/{db_name}/posts/{post_id}/comments',
      CREATE: '/api/v1/databases/{db_name}/posts/{post_id}/comments',
      GET: '/api/v1/databases/{db_name}/comments/{comment_id}',
      UPDATE: '/api/v1/databases/{db_name}/comments/{comment_id}',
      DELETE: '/api/v1/databases/{db_name}/comments/{comment_id}',
    }
  },
  
  // Request timeout in milliseconds
  TIMEOUT: 10000,
  
  // Retry configuration
  RETRY: {
    MAX_ATTEMPTS: 3,
    DELAY: 1000,
  }
};

// Check if backend is available
export const isBackendAvailable = () => {
  // Always use backend when BASE_URL is set to production URL
  return API_CONFIG.BASE_URL === 'https://backend.caronon.com' || 
         (process.env.REACT_APP_API_URL && process.env.REACT_APP_API_URL !== 'http://localhost:8080');
};

// Get API URL for a specific endpoint
export const getApiUrl = (endpoint) => {
  return `${API_CONFIG.BASE_URL}${endpoint}`;
};

// Export configuration
export default API_CONFIG;
