import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import LoadingSpinner from './LoadingSpinner';

// Define whitelist pages that don't require authentication
const WHITELIST_PAGES = [
  '/',
  '/login',
  '/register',
  '/about',
  '/contact'
];

const ProtectedRoute = ({ children, requireAuth = true }) => {
  const { isAuthenticated, loading } = useAuth();
  const location = useLocation();
  const currentPath = location.pathname;

  // Check if current page is in whitelist
  const isWhitelisted = WHITELIST_PAGES.includes(currentPath);

  // Show loading spinner while checking authentication
  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <LoadingSpinner size="xl" text="Checking authentication..." />
      </div>
    );
  }

  // If page requires authentication and user is not authenticated
  if (requireAuth && !isAuthenticated && !isWhitelisted) {
    // Redirect to login page with return URL
    return <Navigate to="/login" state={{ from: location }} replace />;
  }

  // If user is authenticated and trying to access login/register pages
  if (isAuthenticated && (currentPath === '/login' || currentPath === '/register')) {
    // Redirect to dashboard
    return <Navigate to="/dashboard" replace />;
  }

  // Allow access to the requested page
  return children;
};

export default ProtectedRoute;
